CREATE PROCEDURE LG_GETEMUHACCUPPERCODE_123
       @accountCode VARCHAR(110),
       @level INT,
       @sBuffer VARCHAR(110) OUTPUT,
       @upperRef INT OUTPUT AS
DECLARE @size INT,
        @sep VARCHAR(1),
        @fndSep INT,
        @cnt INT,
        @i INT
SELECT @sep ='.',
       @size = LEN(@accountCode),
       @cnt = 1,
       @sBuffer = '',
       @fndSep = 0,
       @i = -1,
       @level = @level - 1
 IF    @level < 0
  BEGIN
        SET @sBuffer = ''
        SET    @upperRef = 0
        RETURN
  END
 WHILE @cnt <= @size
  BEGIN
      IF(SUBSTRING(@accountCode,@cnt,1) = @sep)
       SET @fndSep = 1
      ELSE
       SET @fndSep = 0
      IF(@fndSep = 0 OR @i < @level -1)
        SET @sBuffer = @sBuffer + SUBSTRING(@accountCode,@cnt,1)
      IF(@fndSep = 1)
        SET @i = @i + 1
      IF(@i = @level)
       BREAK;
      SET @cnt = @cnt + 1
  END
  SELECT @upperRef = LOGICALREF FROM LG_123_EMUHACC WHERE CODE = @sBuffer
